+        let encoded2 = encoder2
+            .encode_with_id(&snapshot, object_id, Time::ZERO)
+            .unwrap();
+
+        assert_eq!(encoded1.symbols.len(), encoded2.symbols.len());
+        for (s1, s2) in encoded1.symbols.iter().zip(encoded2.symbols.iter()) {
